# تحلیل جامع انقلاب فرانسه — فایل لاتکس، تصویر جلد و اسلایدهای اینستاگرام

در ادامه سه بخش ارائه می‌شود:
1. **فایل لاتکس کامل** (آماده‌ی کامپایل با XeLaTeX)
2. **تصویر جلد SVG**
3. **۱۰ اسلاید اینستاگرام SVG**

---

## ۱. فایل لاتکس نهایی

```latex
% ═══════════════════════════════════════════════════════════════════
%  تحلیل جامع انقلاب فرانسه (۱۷۸۹–۱۷۹۹) و تحولات پس از آن
%  نویسنده: مهدی سالم
%  کامپایل: XeLaTeX
% ═══════════════════════════════════════════════════════════════════
\documentclass[12pt,a4paper]{article}

% ─── بسته‌های پایه ───────────────────────────────────────────
\usepackage{fontspec}
\usepackage{geometry}
\usepackage{xcolor}
\usepackage{colortbl}
\usepackage{booktabs}
\usepackage{longtable}
\usepackage{array}
\usepackage{tabularx}
\usepackage{multirow}
\usepackage{makecell}
\usepackage{tikz}
\usepackage{pgfplots}
\usepackage{tcolorbox}
\usepackage{fancyhdr}
\usepackage{titlesec}
\usepackage{titletoc}
\usepackage{hyperref}
\usepackage{enumitem}
\usepackage{graphicx}
\usepackage{wrapfig}
\usepackage{multicol}
\usepackage{setspace}
\usepackage{amsmath}
\usepackage{amssymb}
\usepackage{footnote}
\usepackage{endnotes}
\usepackage{etoolbox}
\usepackage{calc}
\usepackage{varwidth}
\usepackage{needspace}    % FIXED: اضافه شد — جلوگیری از عنوان یتیم
\usepackage{adjustbox}     % FIXED: اضافه شد — تنظیم اندازه‌ی جداول عریض

% ─── تنظیمات TikZ ─────────────────────────────────────────────
\usetikzlibrary{
  arrows, arrows.meta, positioning, shapes, shapes.geometric,
  shapes.multipart, shadows, decorations, decorations.pathreplacing,
  decorations.markings, patterns, backgrounds, calc, fit,
  mindmap, trees, matrix, chains, scopes,
  fadings, through, plotmarks, intersections
}
\pgfplotsset{compat=1.18}
\tcbuselibrary{skins, breakable}

% ─── صفحه‌آرایی ───────────────────────────────────────────────
\geometry{
  a4paper,
  top=2.8cm, bottom=2.8cm,
  right=3.5cm, left=3cm,
  headheight=1.5cm,
  headsep=0.5cm,
  footskip=1.2cm
}

% ─── پالت رنگی ────────────────────────────────────────────────
\definecolor{PrimaryDeep}{HTML}{1A237E}
\definecolor{PrimaryMid}{HTML}{283593}
\definecolor{PrimaryLight}{HTML}{3949AB}
\definecolor{AccentGold}{HTML}{F9A825}
\definecolor{AccentAmber}{HTML}{FF8F00}
\definecolor{AccentTeal}{HTML}{00695C}
\definecolor{AccentRed}{HTML}{B71C1C}
\definecolor{AccentGreen}{HTML}{1B5E20}
\definecolor{AccentPurple}{HTML}{4A148C}
\definecolor{NeutralLight}{HTML}{ECEFF1}
\definecolor{NeutralMid}{HTML}{B0BEC5}
\definecolor{NeutralDark}{HTML}{455A64}
\definecolor{TextMain}{HTML}{212121}
\definecolor{TextSecond}{HTML}{424242}
\definecolor{BgWarm}{HTML}{FFF8E1}
\definecolor{BgCool}{HTML}{E8EAF6}
\definecolor{BgTeal}{HTML}{E0F2F1}

\definecolor{EraAncient}{HTML}{4E342E}
\definecolor{EraMedieval}{HTML}{37474F}
\definecolor{EraEarlyMod}{HTML}{1565C0}
\definecolor{EraModern}{HTML}{2E7D32}
\definecolor{EraContemp}{HTML}{6A1B9A}
\definecolor{EraPostmod}{HTML}{AD1457}

% رنگ‌های فازها
\definecolor{PhaseLiberal}{HTML}{1565C0}    % FIXED: اضافه شد — رنگ فاز لیبرال
\definecolor{PhaseRadical}{HTML}{B71C1C}    % FIXED: اضافه شد — رنگ فاز رادیکال
\definecolor{PhaseThermidor}{HTML}{F57F17}  % FIXED: اضافه شد — رنگ فاز ترمیدور
\definecolor{PhaseNapoleon}{HTML}{4A148C}   % FIXED: اضافه شد — رنگ فاز ناپلئون

% ─── جعبه‌های محتوایی ─────────────────────────────────────────
\tcbset{
  mybox/.style={
    enhanced, breakable,
    colback=BgCool, colframe=PrimaryMid,
    fonttitle=\bfseries\large,
    attach boxed title to top right={yshift=-2mm, xshift=-3mm},
    boxed title style={colback=PrimaryMid, colframe=PrimaryDeep},
    top=4mm, bottom=4mm,
    before skip=12pt, after skip=12pt,
  },
  defbox/.style={
    enhanced, breakable,
    colback=BgWarm, colframe=AccentGold,
    fonttitle=\bfseries,
    left=4mm, right=4mm,
    borderline west={3pt}{0pt}{AccentAmber},
    sharp corners,
    before skip=12pt, after skip=12pt,
  },
  wavebox/.style={
    enhanced, breakable,
    colback=BgTeal, colframe=AccentTeal,
    fonttitle=\bfseries,
    rounded corners,
    drop shadow,
    before skip=12pt, after skip=12pt,
  },
  quotebox/.style={
    enhanced, breakable,
    colback=NeutralLight, colframe=NeutralDark,
    fontupper=\itshape,
    left=8mm,
    borderline west={4pt}{0pt}{NeutralMid},
    sharp corners=south,
    before skip=12pt, after skip=12pt,
  },
  enemybox/.style={
    enhanced, breakable,
    colback=red!5, colframe=AccentRed,
    fonttitle=\bfseries,
    borderline west={3pt}{0pt}{AccentRed},
    before skip=12pt, after skip=12pt,
  },
}

% ─── سربرگ و پابرگ ────────────────────────────────────────────
\pagestyle{fancy}
\fancyhf{}
\renewcommand{\headrulewidth}{0.6pt}
\renewcommand{\footrulewidth}{0.3pt}
\fancyhead[R]{\small\color{PrimaryMid}\rightmark}
\fancyhead[L]{\small\color{NeutralDark}تحلیل جامع انقلاب فرانسه \textbar{} مهدی سالم}% FIXED: عنوان مقاله
\fancyfoot[C]{\small\thepage}
\fancyfoot[R]{\small\color{NeutralDark}\leftmark}

% ─── عنوان‌بندی بخش‌ها ────────────────────────────────────────
\titleformat{\section}[block]
  {\Large\bfseries\color{PrimaryDeep}}
  {\thesection}{1em}{}
  [{\color{AccentGold}\titlerule[1.5pt]}]

\titleformat{\subsection}[block]
  {\large\bfseries\color{PrimaryMid}}
  {\thesubsection}{0.8em}{}
  [{\color{NeutralMid}\titlerule[0.6pt]}]

\titleformat{\subsubsection}[runin]
  {\normalsize\bfseries\color{AccentTeal}}
  {\thesubsubsection}{0.6em}{}[\ —\ ]

% ─── فاصله‌گذاری ──────────────────────────────────────────────
\titlespacing*{\section}{0pt}{18pt}{10pt}
\titlespacing*{\subsection}{0pt}{14pt}{6pt}
\setlength{\parindent}{1em}
\setlength{\parskip}{0.4em}
\onehalfspacing

% ─── hyperref ─────────────────────────────────────────────────
\hypersetup{
  colorlinks  = true,
  linkcolor   = PrimaryMid,
  citecolor   = AccentTeal,
  urlcolor    = AccentAmber,
  pdftitle    = {تحلیل جامع انقلاب فرانسه},
  pdfauthor   = {مهدی سالم},
  pdfsubject  = {تاریخ سیاسی تطبیقی},
  bookmarks   = true,
  pdfpagemode = UseOutlines,
  pdfencoding = unicode,
}

\usepackage{xepersian} % FIXED: آخرین بسته

% ─── فونت‌ها ────────────────────────────────────────────────
\settextfont{Vazirmatn}
\setlatintextfont[Scale=0.95]{Linux Libertine}
\setdigitfont[Scale=0.95]{Vazirmatn}

% ─── دستورات کمکی ─────────────────────────────────────────────
\newcommand{\concept}[1]{\textbf{\color{PrimaryMid}#1}}
\newcommand{\thinker}[1]{\textit{\color{AccentTeal}#1}}
\newcommand{\era}[1]{\textbf{\color{AccentAmber}#1}}
\newcommand{\enemy}[1]{\textbf{\color{AccentRed}#1}}
\newcommand{\lat}[1]{\lr{#1}}
\newcommand{\src}[1]{\textsuperscript{\scriptsize\color{NeutralDark}[#1]}}

\renewcommand{\thefootnote}{\arabic{footnote}}

% ═══════════════════════════════════════════════════════════════════
\begin{document}

% ─────────────────────────────────────────────────────────────────
%   صفحه‌ی عنوان
% ─────────────────────────────────────────────────────────────────
\begin{titlepage}
\begin{tikzpicture}[remember picture, overlay]
  % --- پس‌زمینه ---
  \fill[PrimaryDeep] (current page.south west) rectangle (current page.north east);%
  % --- دایره‌های تزئینی ---
  \fill[white, opacity=0.04] (2,4) circle (3.5);%
