  % --- نوار طلایی افقی ---
  \fill[AccentGold] (0,14.5) rectangle (21,14.7);%
  \fill[AccentGold] (0,10.8) rectangle (21,11.0);%
  % --- عنوان اصلی ---
  \node[text=white, font=\fontsize{32}{38}\selectfont\bfseries

